// Verify JWT session
const token = items[0].json.headers.authorization.split(' ')[1];
// In production, use a library to verify the token secret
// For demo, we extract the student_id
const decoded = JSON.parse(Buffer.from(token.split('.')[1], 'base64').toString());
return [{ json: { student_id: decoded.student_id, message: items[0].json.body.message } }];
